/**
 * @summary Listar usuários do sistema (Admin)
 */
export const getListUsuariosUrl = (params?: ListUsuariosParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/usuarios?${stringifiedParams}`
    : `/api/v1/usuarios`;
};

export const listUsuarios = async (
  params?: ListUsuariosParams,
  options?: RequestInit,
): Promise<PaginatedUsuarios> => {
  return customFetch<PaginatedUsuarios>(getListUsuariosUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListUsuariosQueryKey = (params?: ListUsuariosParams) => {
  return [`/api/v1/usuarios`, ...(params ? [params] : [])] as const;
};

export const getListUsuariosQueryOptions = <
  TData = Awaited<ReturnType<typeof listUsuarios>>,
  TError = ErrorType<ErrorResponse>,
>(
  params?: ListUsuariosParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listUsuarios>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListUsuariosQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listUsuarios>>> = ({
    signal,
  }) => listUsuarios(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listUsuarios>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListUsuariosQueryResult = NonNullable<
  Awaited<ReturnType<typeof listUsuarios>>
>;
export type ListUsuariosQueryError = ErrorType<ErrorResponse>;

